   320→				return(ld->ld_errno);
   321→			}
   322→			tag = ber_peek_tag( ber, &berLen );
   323→		}
   324→
   325→		if ( chgnumpresentp != NULL || chgnump != NULL ) {
   326→			ber_int_t chgnum = 0;
   327→			int present = 0;
