		return(ld->ld_errno);
	}

	if ( prevdnp != NULL ) {
		BER_BVZERO( prevdnp );
	}
	if ( chgnumpresentp != NULL )
		*chgnumpresentp = 0;
	if ( chgnump != NULL )
		*chgnump = 0;

	/* Extract the change type from the control. */
	tag = ber_scanf(ber, "{e" /*}*/, &chgtype);

	if( tag != LBER_ENUMERATED ) {
		ber_free(ber, 1);
		ld->ld_errno = LDAP_DECODING_ERROR;
		return(ld->ld_errno);
	}
	if ( chgtypep != NULL )
		*chgtypep = chgtype;

	tag = ber_peek_tag( ber, &berLen );
	if ( berLen ) {
		if (tag == LBER_OCTETSTRING) {
			if (prevdnp != NULL) {
				tag = ber_get_stringbv( ber, prevdnp, 0 );
			} else {
				struct berval bv;
				tag = ber_skip_element( ber, &bv );
			}
			if ( tag == LBER_ERROR ) {
				ber_free(ber, 1);
				ld->ld_errno = LDAP_DECODING_ERROR;
				return(ld->ld_errno);
			}
			tag = ber_peek_tag( ber, &berLen );
		}

		if ( chgnumpresentp != NULL || chgnump != NULL ) {
			ber_int_t chgnum = 0;
			int present = 0;
			if (tag == LBER_INTEGER) {
				present = 1;
				tag = ber_get_int( ber, &chgnum );
				if ( tag == LBER_ERROR ) {
					ber_free(ber, 1);
					ld->ld_errno = LDAP_DECODING_ERROR;
					return(ld->ld_errno);
				}
				if ( chgnumpresentp != NULL )
					*chgnumpresentp = present;
				if ( chgnump != NULL )
					*chgnump = chgnum;
			}
		}
	}

	ber_free(ber,1);

	ld->ld_errno = LDAP_SUCCESS;
	return(ld->ld_errno);
}

